function ModelCrusadeAgainst:InitDreamCrusadeCheckpointRef()
    local list = {}
    for i, v in pairs(GameTable.DreamCrusadeCheckpointRef) do
        local boosType = v.boosType
        local difficulty = v.difficulty

        local typeList = list[boosType] or {}
        local difficultyList = typeList[difficulty] or {}
        table.insert(difficultyList, v)

        typeList[difficulty] = difficultyList
        list[boosType] = typeList
    end
    for i, v in pairs(list) do
        for j, k in pairs(v) do
            table.sort(k, function(a, b)
                return a.levelNum < b.levelNum
            end)
        end
    end
    self._list = list
end
