function ModelCrusadeAgainst:CheckIsOpen(openDay)
    local week = LUtil.GetWeekByTime()
    local openDay = string.split(openDay, ";")
    for j, k in ipairs(openDay) do
        if week == tonumber(k) then
            return true
        end
    end
    return false
end

function ModelCrusadeAgainst:GetOpenDayStr(openDay)
    local dayStrList = {
        32363, 32364, 32365, 32366, 32367, 32368, 32369
    }

    local openDayStr = ""
    local openDayArr = string.split(openDay, ";")
    local len = #openDayArr
    for i, v in ipairs(openDayArr) do
        local str = v

        local textId = dayStrList[tonumber(v)]
        if textId then
            str = ccClientText(textId)
        end
        openDayStr = openDayStr .. str
        if len ~= i then
            openDayStr = openDayStr .. "/"
        end
    end
    return openDayStr
end
